class MyLinkedList {
public:
    struct ListNode {
        int val;
        ListNode* next;
        ListNode(int x) : val(x), next(nullptr) {}
    };

    MyLinkedList() : head_(nullptr), size_(0) {}

    int get(int index) {
        if (index < 0 || index >= size_) return -1;
        ListNode* curr = head_;
        for (int i = 0; i < index; ++i) {
            curr = curr->next;
        }
        return curr->val;
    }

    void addAtHead(int val) {
        ListNode* newNode = new ListNode(val);
        newNode->next = head_;
        head_ = newNode;
        ++size_;
    }

    void addAtTail(int val) {
        ListNode* newNode = new ListNode(val);
        if (!head_) {
            head_ = newNode;
        } else {
            ListNode* curr = head_;
            while (curr->next) {
                curr = curr->next;
            }
            curr->next = newNode;
        }
        ++size_;
    }

    void addAtIndex(int index, int val) {
        if (index < 0 || index > size_) return;
        if (index == 0) {
            addAtHead(val);
        } else if (index == size_) {
            addAtTail(val);
        } else {
            ListNode* newNode = new ListNode(val);
            ListNode* curr = head_;
            for (int i = 0; i < index - 1; ++i) {
                curr = curr->next;
            }
            newNode->next = curr->next;
            curr->next = newNode;
            ++size_;
        }
    }

    void deleteAtIndex(int index) {
        if (index < 0 || index >= size_) return;
        if (index == 0) {
            ListNode* temp = head_;
            head_ = head_->next;
            delete temp;
        } else {
            ListNode* curr = head_;
            for (int i = 0; i < index - 1; ++i) {
                curr = curr->next;
            }
            ListNode* temp = curr->next;
            curr->next = curr->next->next;
            delete temp;
        }
        --size_;
    }

private:
    ListNode* head_;
    int size_;
};

